{
  "namespace": {
    "apiName": "user-service",
    "client": "demo"
  },
  "description": "Create a REST API for managing users with endpoints to get all users, get user by ID, create new user, update user, and delete user. Include proper error responses for not found (404) and validation errors (400).",
  "useExistingSpec": false,
  "context": {
    "domain": "user management",
    "style": "RESTful"
  },
  "options": {
    "includeExamples": true,
    "generateErrorCases": true,
    "realisticData": true
  }
}

{
  "namespace": {
    "apiName": "enhanced-petstore",
    "client": "demo"
  },
  "specification": "openapi: 3.0.0\ninfo:\n  title: Pet Store API\n  version: 1.0.0\npaths:\n  /pets:\n    get:\n      operationId: getPets\n      responses:\n        '200':\n          description: Success",
  "format": "OPENAPI_3",
  "description": "Enhance this API with realistic pet data including different breeds, ages, and adoption statuses. Add error scenarios for when the pet store is closed or when there are no pets available.",
  "options": {
    "includeExamples": true,
    "generateErrorCases": true,
    "realisticData": true
  }
}
